     1|/**
     2| * IVX durable data root resolver.
     3| *
     4| * THE DATA-LOSS FIX (2026-06-07):
     5| *   Every IVX business store (leads, deals, investor CRM, outreach, capital
     6| *   pipeline, etc.) historically wrote to `process.cwd()/logs/audit/...`. On
     7| *   Render that path lives on the EPHEMERAL container filesystem, so every deploy
     8| *   or restart wiped all business data back to zero — deals 3 → 0, CRM → 0, leads
     9| *   reset. Meanwhile the chat SQLite correctly lives on the mounted PERSISTENT
    10| *   disk at `/app/data` (see render.yaml `disk.mountPath: /app/data` and
    11| *   `CHAT_DATABASE_PATH=/app/data/chat-room.sqlite`).
    12| *
    13| *   This module centralises the durable base directory so all stores write under
    14| *   the persistent disk and survive restarts/deploys.
    15| *
    16| * Resolution order:
    17| *   1. `IVX_DATA_DIR` env var, if set (explicit override; set to /app/data in prod).
    18| *   2. The mounted persistent disk `/app/data`, if it exists and is writable.
    19| *   3. `process.cwd()` (local dev / tests — keeps the existing layout).
    20| *
    21| * The chosen root is cached after the first resolve so every store agrees on one
    22| * location for the life of the process.
    23| */
    24|import { existsSync, mkdirSync, accessSync, constants, cpSync } from 'node:fs';
    25|import path from 'node:path';
    26|
    27|let cachedRoot: string | null = null;
    28|
    29|function isUsableDir(dir: string): boolean {
    30|  try {
    31|    if (!existsSync(dir)) {
    32|      // Try to create it — the mount point may exist but the subdir may not.
    33|      mkdirSync(dir, { recursive: true });
    34|    }
    35|    accessSync(dir, constants.W_OK);
    36|    return true;
    37|  } catch {
    38|    return false;
    39|  }
    40|}
    41|
    42|/**
    43| * Resolve the durable base directory for all IVX persistent business data.
    44| * Stores should build their paths as `path.join(resolveDataRoot(), 'logs', 'audit', '<store>')`.
    45| */
    46|export function resolveDataRoot(): string {
    47|  if (cachedRoot) return cachedRoot;
    48|
    49|  const explicit = typeof process.env.IVX_DATA_DIR === 'string' ? process.env.IVX_DATA_DIR.trim() : '';
    50|  if (explicit && isUsableDir(explicit)) {
    51|    cachedRoot = explicit;
    52|    return cachedRoot;
    53|  }
    54|
    55|  const renderDisk = '/app/data';
    56|  if (isUsableDir(renderDisk)) {
    57|    cachedRoot = renderDisk;
    58|    return cachedRoot;
    59|  }
    60|
    61|  cachedRoot = process.cwd();
    62|  return cachedRoot;
    63|}
    64|
    65|/** Convenience: build a path under the durable audit root, e.g. auditDir('lead-capture'). */
    66|export function auditDir(...segments: string[]): string {
    67|  return path.join(resolveDataRoot(), 'logs', 'audit', ...segments);
    68|}
    69|
    70|/**
    71| * Business-data store subdirectories under logs/audit that must persist. Used by the
    72| * one-time migration to carry pre-fix data from the old ephemeral location
    73| * (process.cwd()) onto the durable disk without overwriting anything already there.
    74| */
    75|const DURABLE_STORE_DIRS: readonly string[] = [
    76|  'lead-capture',
    77|  'investor-crm',
    78|  'deal-tracking',
    79|  'deal-packet',
    80|  'outreach',
    81|  'capital-pipeline',
    82|  'capital-network',
    83|];
    84|
    85|let migrationDone = false;
    86|
    87|/**
    88| * One-time, idempotent migration: if the durable root differs from process.cwd()
    89| * (i.e. we're on the Render persistent disk) and a business store exists in the old
    90| * cwd location but NOT yet on the durable disk, copy it over so historical leads,
    91| * deals, and CRM contacts are preserved on the first boot after the data-loss fix.
    92| * Never overwrites existing durable data. Best-effort: failures never block boot.
    93| */
    94|export function migrateLegacyDataIntoDataRoot(): { migrated: string[]; skipped: string[] } {
    95|  const migrated: string[] = [];
    96|  const skipped: string[] = [];
    97|  if (migrationDone) return { migrated, skipped };
    98|  migrationDone = true;
    99|
   100|  const root = resolveDataRoot();
   101|  const legacyRoot = process.cwd();
   102|  // Nothing to do when the durable root IS the cwd (local dev / tests).
   103|  if (path.resolve(root) === path.resolve(legacyRoot)) return { migrated, skipped };
   104|
   105|  for (const store of DURABLE_STORE_DIRS) {
   106|    try {
   107|      const from = path.join(legacyRoot, 'logs', 'audit', store);
   108|      const to = path.join(root, 'logs', 'audit', store);
   109|      if (!existsSync(from)) continue;
   110|      // Never overwrite durable data that already exists.
   111|      if (existsSync(to)) {
   112|        skipped.push(store);
   113|        continue;
